O Plotly.js utiliza JavaScript, que suporta operações matemáticas nativas. Aqui estão algumas das principais:



Operação
Sintaxe JavaScript
Exemplo (y = f(x))




Soma
a + b
y = x + 2


Subtração
a - b
y = x - 3


Multiplicação
a * b
y = x * 2


Divisão
a / b
y = x / 2


Potência
Math.pow(a, b)
y = Math.pow(x, 2)


Raiz quadrada
Math.sqrt(x)
y = Math.sqrt(x)


Logaritmo
Math.log(x)
y = Math.log(x)


Exponencial
Math.exp(x)
y = Math.exp(x)









var x_values = [...Array(100).keys()].map(i =&gt; i / 10); // x de 0 a 10

var log_trace = {
    x: x_values,
    y: x_values.map(x =&gt; Math.log(x + 1)), // log(x + 1) para evitar log(0)
    type: 'scatter',
    mode: 'lines',
    line: { color: 'red' },
    name: 'log(x + 1)'
};

var exp_trace = {
    x: x_values,
    y: x_values.map(x =&gt; Math.exp(x / 3)), // e^(x/3)
    type: 'scatter',
    mode: 'lines',
    line: { color: 'blue' },
    name: 'exp(x/3)'
};

var quad_trace = {
    x: x_values,
    y: x_values.map(x =&gt; Math.pow(x, 2)), // x²
    type: 'scatter',
    mode: 'lines',
    line: { color: 'green' },
    name: 'x²'
};

Plotly.newPlot('grafico', [log_trace, exp_trace, quad_trace]);









var x_values = [...Array(100).keys()].map(i =&gt; i / 10);

var complex_trace = {
    x: x_values,
    y: x_values.map(x =&gt; Math.sin(x) * Math.exp(-x / 5) + 2),
    type: 'scatter',
    mode: 'lines',
    line: { color: 'purple' },
    name: 'sin(x) * e^(-x/5) + 2'
};

Plotly.newPlot('grafico', [complex_trace]);







Gráficos de superfície 3D precisam de uma matriz de valores Z, gerada a partir de valores X e Y.

📌 Exemplo 3: Superfície 3D - Função Seno

var x_values = [...Array(30).keys()].map(i =&gt; i - 15); // x de -15 a 15
var y_values = [...Array(30).keys()].map(i =&gt; i - 15); // y de -15 a 15

// Criar matriz de Z com f(x, y) = sen(sqrt(x² + y²))
var z_values = x_values.map(x =&gt;
